namespace sv_3ab2c9a769764ad697db7e6ebaa32621.Services;

public class ApplicationWizardState
{
    // Step 1 — Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 — Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3 — References
    public List<ReferenceContact> References { get; set; } = [];

    public bool IsStepCompleted(int step) => step switch
    {
        1 => !string.IsNullOrWhiteSpace(Name) && !string.IsNullOrWhiteSpace(Email),
        2 => JobHistory.Count > 0,
        3 => References.Count > 0,
        _ => false
    };
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState

<div class="container py-4">
    <h3 class="mb-3">Job Application</h3>

    <nav class="mb-4">
        <ol class="list-group list-group-horizontal text-center">
            @for (int i = 0; i < _steps.Length; i++)
            {
                var step = _steps[i];
                var stepNumber = i + 1;
                var isCurrent = stepNumber == CurrentStep;
                var isCompleted = WizardState.IsStepCompleted(stepNumber);

                <li class="list-group-item flex-fill @(isCurrent ? "active" : "") @(isCompleted && !isCurrent ? "list-group-item-success" : "")">
                    <a href="@step.Url" class="text-decoration-none @(isCurrent ? "text-white" : "")">
                        Step @stepNumber: @step.Label
                        @if (isCompleted)
                        {
                            <span>&#10003;</span>
                        }
                    </a>
                </li>
            }
        </ol>
    </nav>

    <div class="progress mb-4" style="height: 6px;">
        <div class="progress-bar" role="progressbar"
             style="width: @((CurrentStep) * 25)%"></div>
    </div>

    @Body
</div>

@code {
    private record StepInfo(string Url, string Label);

    private static readonly StepInfo[] _steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review")
    ];

    private int CurrentStep
    {
        get
        {
            var path = new Uri(Nav.Uri).AbsolutePath;
            for (int i = 0; i < _steps.Length; i++)
            {
                if (path.Equals(_steps[i].Url, StringComparison.OrdinalIgnoreCase))
                    return i + 1;
            }
            return 1;
        }
    }
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 1: Personal Info</PageTitle>

<h4>Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="WizardState.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="WizardState.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next" disabled="@(!CanProceed)">
        Next &rarr;
    </button>
</div>

@code {
    private bool CanProceed =>
        !string.IsNullOrWhiteSpace(WizardState.Name) &&
        !string.IsNullOrWhiteSpace(WizardState.Email);

    private void Next() => Nav.NavigateTo("/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 2: Experience</PageTitle>

<h4>Job History</h4>

@foreach (var entry in WizardState.JobHistory)
{
    <div class="card mb-2 p-2">
        <strong>@entry.Title</strong> at @entry.Company (@entry.Years)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h6>Add Entry</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="_company" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Job Title" @bind="_title" />
        </div>
        <div class="col-md-2">
            <input class="form-control" placeholder="Years" @bind="_years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="AddEntry"
                    disabled="@(!CanAdd)">Add</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="@(() => Nav.NavigateTo("/apply/personal-info"))">
        &larr; Back
    </button>
    <button class="btn btn-primary" @onclick="@(() => Nav.NavigateTo("/apply/references"))"
            disabled="@(WizardState.JobHistory.Count == 0)">
        Next &rarr;
    </button>
</div>

@code {
    private string _company = string.Empty;
    private string _title = string.Empty;
    private string _years = string.Empty;

    private bool CanAdd =>
        !string.IsNullOrWhiteSpace(_company) &&
        !string.IsNullOrWhiteSpace(_title) &&
        !string.IsNullOrWhiteSpace(_years);

    private void AddEntry()
    {
        WizardState.JobHistory.Add(new()
        {
            Company = _company,
            Title = _title,
            Years = _years
        });
        _company = _title = _years = string.Empty;
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 3: References</PageTitle>

<h4>Reference Contacts</h4>

@foreach (var r in WizardState.References)
{
    <div class="card mb-2 p-2">
        <strong>@r.Name</strong> — @r.Email (@r.Relationship)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h6>Add Reference</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Name" @bind="_name" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Email" @bind="_email" />
        </div>
