            {
                var step = _steps[i];
                var stepNumber = i + 1;
                var isCurrent = stepNumber == CurrentStep;
                var isCompleted = WizardState.IsStepCompleted(stepNumber);

                <li class="list-group-item flex-fill @(isCurrent ? "active" : "") @(isCompleted && !isCurrent ? "list-group-item-success" : "")">
                    <a href="@step.Url" class="text-decoration-none @(isCurrent ? "text-white" : "")">
                        Step @stepNumber: @step.Label
                        @if (isCompleted)
                        {
                            <span>&#10003;</span>
                        }
                    </a>
                </li>
            }
        </ol>
    </nav>

    <div class="progress mb-4" style="height: 6px;">
        <div class="progress-bar" role="progressbar"
             style="width: @((CurrentStep) * 25)%"></div>
    </div>

    @Body
</div>

@code {
    private record StepInfo(string Url, string Label);

    private static readonly StepInfo[] _steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review")
    ];

    private int CurrentStep
    {
        get
        {
            var path = new Uri(Nav.Uri).AbsolutePath;
            for (int i = 0; i < _steps.Length; i++)
            {
                if (path.Equals(_steps[i].Url, StringComparison.OrdinalIgnoreCase))
                    return i + 1;
            }
            return 1;
        }
    }
}

