toolArgs.file_text:
@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 1: Personal Info</PageTitle>

<h4>Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="WizardState.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="WizardState.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next" disabled="@(!CanProceed)">
        Next &rarr;
    </button>
</div>

@code {
    private bool CanProceed =>
        !string.IsNullOrWhiteSpace(WizardState.Name) &&
        !string.IsNullOrWhiteSpace(WizardState.Email);

    private void Next() => Nav.NavigateTo("/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 2: Experience</PageTitle>

<h4>Job History</h4>

@foreach (var entry in WizardState.JobHistory)
{
    <div class="card mb-2 p-2">
        <strong>@entry.Title</strong> at @entry.Company (@entry.Years)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h6>Add Entry</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="_company" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Job Title" @bind="_title" />
        </div>
        <div class="col-md-2">
            <input class="form-control" placeholder="Years" @bind="_years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="AddEntry"
                    disabled="@(!CanAdd)">Add</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="@(() => Nav.NavigateTo("/apply/personal-info"))">
        &larr; Back
    </button>
    <button class="btn btn-primary" @onclick="@(() => Nav.NavigateTo("/apply/references"))"
            disabled="@(WizardState.JobHistory.Count == 0)">
        Next &rarr;
    </button>
</div>

@code {
    private string _company = string.Empty;
    private string _title = string.Empty;
    private string _years = string.Empty;

    private bool CanAdd =>
        !string.IsNullOrWhiteSpace(_company) &&
        !string.IsNullOrWhiteSpace(_title) &&
        !string.IsNullOrWhiteSpace(_years);

    private void AddEntry()
    {
        WizardState.JobHistory.Add(new()
        {
            Company = _company,
            Title = _title,
            Years = _years
        });
        _company = _title = _years = string.Empty;
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 3: References</PageTitle>

<h4>Reference Contacts</h4>

@foreach (var r in WizardState.References)
{
    <div class="card mb-2 p-2">
        <strong>@r.Name</strong> — @r.Email (@r.Relationship)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h6>Add Reference</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Name" @bind="_name" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Email" @bind="_email" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Relationship" @bind="_relationship" />
        </div>
    </div>
    <button class="btn btn-outline-secondary mt-2" @onclick="AddReference"
            disabled="@(!CanAdd)">Add</button>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="@(() => Nav.NavigateTo("/apply/experience"))">
        &larr; Back
    </button>
    <button class="btn btn-primary" @onclick="@(() => Nav.NavigateTo("/apply/review"))"
            disabled="@(WizardState.References.Count == 0)">
        Next &rarr;
    </button>
</div>

@code {
    private string _name = string.Empty;
    private string _email = string.Empty;
    private string _relationship = string.Empty;

    private bool CanAdd =>
        !string.IsNullOrWhiteSpace(_name) &&
        !string.IsNullOrWhiteSpace(_email) &&
        !string.IsNullOrWhiteSpace(_relationship);

    private void AddReference()
    {
        WizardState.References.Add(new()
        {
            Name = _name,
            Email = _email,
            Relationship = _relationship
        });
        _name = _email = _relationship = string.Empty;
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_3ab2c9a769764ad697db7e6ebaa32621.Services.ApplicationWizardState WizardState
@inject NavigationManager Nav

<PageTitle>Step 4: Review</PageTitle>

<h4>Review Your Application</h4>

<div class="card mb-3">
    <div class="card-header">Personal Information</div>
    <div class="card-body">
        <p><strong>Name:</strong> @WizardState.Name</p>
        <p><strong>Email:</strong> @WizardState.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header">Experience</div>
    <div class="card-body">
        @foreach (var job in WizardState.JobHistory)
        {
            <p>@job.Title at @job.Company — @job.Years</p>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header">References</div>
    <div class="card-body">
        @foreach (var r in WizardState.References)
        {
            <p>@r.Name — @r.Email (@r.Relationship)</p>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="@(() => Nav.NavigateTo("/apply/references"))">
        &larr; Back
    </button>
    <button class="btn btn-success" @onclick="Submit">
        Submit Application
    </button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool _submitted;

    private void Submit()
    {
        _submitted = true;
    }
}

